import axios from "axios";

const api = axios.create({
  baseURL: process.env.REACT_APP_API_URL || "http://localhost:8080",
});

api.interceptors.request.use(
  (config) => {
    const token = localStorage.getItem("token");
    console.log(`📤 [${config.method.toUpperCase()}] ${config.url}`);
    console.log(`🔑 Token disponible: ${token ? "SÍ (" + token.substring(0, 20) + "...)" : "NO"}`);

    if (token) {
      config.headers["Authorization"] = `Bearer ${token}`;
      console.log(`✅ Header Authorization añadido`);
    } else {
      console.warn(`⚠️ ADVERTENCIA: No hay token en localStorage`);
    }
    return config;
  },
  (error) => {
    console.error(`❌ Error en interceptor de request:`, error);
    return Promise.reject(error);
  },
);

api.interceptors.response.use(
  (response) => {
    console.log(`✅ Respuesta exitosa [${response.status}] ${response.config.url}`);
    return response;
  },
  (error) => {
    console.log(`🔴 Error de respuesta [${error.response?.status}] ${error.config?.url}`);
    console.log(`   Mensaje: ${error.response?.data?.message || error.message}`);

    // No procesar errores de login aquí - déja que LoginPage los maneje
    if (error.config && error.config.url.includes("/auth/login")) {
      return Promise.reject(error);
    }

    // Solo redirigir a login si el token es completamente inválido (401) 
    // pero NO para otros endpoints que fallan
    if (error.response && error.response.status === 401) {
      const token = localStorage.getItem("token");
      // Solo redirigir si tenemos token pero el servidor dice que es inválido
      // Si es un error en otro endpoint (crear tarea, etc), déjalo pasar
      if (token && error.config && error.config.url.includes("/auth")) {
        console.warn(`🚪 Token inválido en endpoint de autenticación. Redirigiendo a login...`);
        localStorage.removeItem("token");
        localStorage.removeItem("loggedUser");
        window.location.href = "/login";
      }
      return Promise.reject(error);
    }

    return Promise.reject(error);
  },
);

export default api;
